    public function assign(){ try { $this->ensureBridge(); $apply=request()->get('apply')=='1'; $count=max(1,min(50,(int)request()->get('count',4))); $ids=$this->parseIds(request()->get('tables','')); $user=$this->userInfo(); $tables=$this->enabledTables(); if(!$ids) $ids=array_slice(array_map(fn($t)=>(int)$t['table_id'],$tables),0,$count); $selected=array_values(array_filter($tables,fn($t)=>in_array((int)$t['table_id'],$ids,true))); if($apply) foreach($selected as $t) $this->assignTable((int)$user['staff_id'],$t,$user); return Response::json(['ok'=>true,'version'=>'v106','mode'=>$apply?'APPLIED':'DRY_RUN','selected'=>$selected]); } catch (\Throwable $e){ return $this->err($e); } }
    public function merge(){ try { $this->ensureBridge(); $apply=request()->get('apply')=='1'; $p=(int)request()->get('primary'); $s=(int)request()->get('secondary'); if(!$p||!$s||$p===$s) return Response::json(['ok'=>false,'version'=>'v106','error'=>'primary and secondary table ids required'],422); if($apply){ DB::table('pmd_table_merges')->where('secondary_table_id',$s)->where('status','active')->update(['status'=>'inactive','updated_at'=>date('Y-m-d H:i:s')]); DB::table('pmd_table_merges')->insert(['primary_table_id'=>$p,'secondary_table_id'=>$s,'status'=>'active','staff_id'=>(int)$this->userInfo()['staff_id'],'notes'=>'Created from v106 floor merge','created_at'=>date('Y-m-d H:i:s'),'updated_at'=>date('Y-m-d H:i:s')]); } return Response::json(['ok'=>true,'version'=>'v106','mode'=>$apply?'APPLIED':'DRY_RUN','primary'=>$p,'secondary'=>$s]); } catch (\Throwable $e){ return $this->err($e); } }
    public function resetTables(){ try { $this->ensureBridge(); $apply=request()->get('apply')=='1'; $confirm=request()->get('confirm'); $count=max(1,min(60,(int)request()->get('count',12))); if(!$apply||$confirm!=='REBUILD') return Response::json(['ok'=>true,'version'=>'v106','mode'=>'DRY_RUN','warning'=>'This disables current enabled tables and creates new clean enabled tables. It does NOT delete rows, to protect orders/reservations.','run'=>'/admin/pmd-waiter-floor-v106-reset-tables?apply=1&confirm=REBUILD&count='.$count]); $cols=$this->columns('tables'); DB::beginTransaction(); if(in_array('table_status',$cols,true)) DB::table('tables')->update(['table_status'=>0,'updated_at'=>date('Y-m-d H:i:s')]); $created=[]; for($i=1;$i<=$count;$i++){ $r=[]; if(in_array('table_no',$cols,true)) $r['table_no']=(string)$i; if(in_array('table_name',$cols,true)) $r['table_name']='Table '.$i; if(in_array('pos_table_label',$cols,true)) $r['pos_table_label']='Table '.$i; if(in_array('min_capacity',$cols,true)) $r['min_capacity']=1; if(in_array('max_capacity',$cols,true)) $r['max_capacity']=4; if(in_array('extra_capacity',$cols,true)) $r['extra_capacity']=0; if(in_array('priority',$cols,true)) $r['priority']=$i; if(in_array('is_joinable',$cols,true)) $r['is_joinable']=1; if(in_array('table_status',$cols,true)) $r['table_status']=1; if(in_array('created_at',$cols,true)) $r['created_at']=date('Y-m-d H:i:s'); if(in_array('updated_at',$cols,true)) $r['updated_at']=date('Y-m-d H:i:s'); $created[]=DB::table('tables')->insertGetId($r); } DB::commit(); return Response::json(['ok'=>true,'version'=>'v106','created_table_ids'=>$created]); } catch (\Throwable $e){ try{DB::rollBack();}catch(\Throwable $x){} return $this->err($e); } }

    protected function payload(){ $user=$this->userInfo(); $assigned=$this->assignedIds($user); $merges=$this->mergeMap(); $tables=[]; foreach($this->enabledTables() as $t){ $id=(int)$t['table_id']; $open=$this->openOrders($id,$t); $ready=$this->readyItems($id,$t); $due=$this->due($id,$t); $res=$this->reservation($id); $att=$this->attention($id); $isAssigned=in_array($id,$assigned,true); $merged=$merges[$id]??null; $status='free'; if($merged)$status='merged'; elseif($att['count']>0)$status='attention'; elseif($ready>0)$status='ready'; elseif($due>0)$status='unpaid'; elseif($open>0)$status='open'; elseif($res['count']>0)$status='reserved'; elseif($isAssigned)$status='assigned'; $tables[]=array_merge($t,['assigned'=>$isAssigned,'merged'=>$merged,'floor_status'=>$status,'open_order_count'=>$open,'ready_count'=>$ready,'due_amount'=>$due,'due_label'=>$this->money($due),'reservation'=>$res,'attention'=>$att,'edit_url'=>'/admin/tables/edit/'.$id]); }
