    protected function enabledTables(){ if(!Schema::hasTable('tables')) return []; $c=$this->columns('tables'); $q=DB::table('tables'); if(in_array('table_status',$c,true)) $q->where('table_status',1); if(in_array('priority',$c,true)) $q->orderBy('priority'); elseif(in_array('table_no',$c,true)) $q->orderBy('table_no'); else $q->orderBy('table_id'); $out=[]; foreach($q->limit(250)->get() as $row){ $r=(array)$row; $id=(int)($r['table_id']??$r['id']??0); if(!$id) continue; $no=trim((string)($r['table_no']??$id)); $label=trim((string)($r['pos_table_label']??$r['table_name']??'')); if($label==='') $label='Table '.$no; if(preg_match('/cashier|delivery|takeaway|pickup|counter/i',strtolower($label))) continue; $out[]=['table_id'=>$id,'id'=>$id,'number'=>$no,'label'=>$label,'min_capacity'=>(int)($r['min_capacity']??1),'max_capacity'=>(int)($r['max_capacity']??4),'is_joinable'=>(int)($r['is_joinable']??0),'priority'=>(int)($r['priority']??$id),'enabled'=>true]; } return $out; }
    protected function enabledMenus(){ if(!Schema::hasTable('menus')) return []; $c=$this->columns('menus'); $q=DB::table('menus'); if(in_array('menu_status',$c,true)) $q->where('menu_status',1); if(in_array('is_stock_out',$c,true)) $q->where(fn($qq)=>$qq->whereNull('is_stock_out')->orWhere('is_stock_out',0)); if(in_array('menu_priority',$c,true)) $q->orderBy('menu_priority'); elseif(in_array('menu_name',$c,true)) $q->orderBy('menu_name'); $out=[]; foreach($q->limit(500)->get() as $row){ $r=(array)$row; $id=(int)($r['menu_id']??$r['id']??0); $name=trim((string)($r['menu_name']??$r['name']??'')); if(!$id||$name==='') continue; if(preg_match('/PMD\s+(Ready|Test)|fake|sample/i',$name)) continue; $price=(float)($r['menu_price']??0); if($price<=0) $price=$this->menuPrice($id,$price); $out[]=['id'=>$id,'menu_id'=>$id,'name'=>$name,'price'=>$price,'price_label'=>$this->money($price),'category_id'=>$r['menu_category_id']??null,'prep_time_minutes'=>$r['prep_time_minutes']??null,'edit_url'=>'/admin/menus/edit/'.$id,'source'=>'menus']; } return $out; }
    protected function menuPrice($id,$fallback){ if(!Schema::hasTable('menu_prices')) return $fallback; $c=$this->columns('menu_prices'); if(!in_array('menu_id',$c,true)||!in_array('price',$c,true)) return $fallback; try{ $q=DB::table('menu_prices')->where('menu_id',$id); if(in_array('is_active',$c,true)) $q->where('is_active',1); if(in_array('priority',$c,true)) $q->orderBy('priority'); $row=$q->first(); return $row?(float)((array)$row)['price']:$fallback; } catch (\Throwable $e){ return $fallback; } }

    protected function ordersFor($id,$t){ $q=DB::table('orders'); $c=$this->columns('orders'); $no=(string)($t['number']??$id); $label=(string)($t['label']??('Table '.$no)); return $q->where(function($qq) use($c,$id,$no,$label){ if(in_array('table_id',$c,true)) $qq->orWhere('table_id',$id); if(in_array('location_table_id',$c,true)) $qq->orWhere('location_table_id',$id); if(in_array('table_no',$c,true)) $qq->orWhere('table_no',$no); if(in_array('table_number',$c,true)) $qq->orWhere('table_number',$no); if(in_array('order_type',$c,true)) $qq->orWhere('order_type',(string)$id)->orWhere('order_type',$no)->orWhere('order_type','Table '.$no)->orWhere('order_type',$label); }); }
    protected function openOrders($id,$t){ if(!Schema::hasTable('orders')) return 0; try{ $q=$this->ordersFor($id,$t); $c=$this->columns('orders'); if(in_array('processed',$c,true)) $q->where('processed',0); return (int)$q->count(); } catch (\Throwable $e){ return 0; } }
    protected function due($id,$t){ if(!Schema::hasTable('orders')) return 0; $c=$this->columns('orders'); $total=$this->pick($c,['order_total','total','total_amount','grand_total']); if(!$total) return 0; try{ $q=$this->ordersFor($id,$t); if(in_array('processed',$c,true)) $q->where('processed',0); return (float)$q->sum($total); } catch (\Throwable $e){ return 0; } }
    protected function readyItems($id,$t){ if(!Schema::hasTable('orders')||!Schema::hasTable('order_menus')) return 0; try{ $oc=$this->columns('orders'); $mc=$this->columns('order_menus'); $pk=$this->pick($oc,['order_id','id']); $fk=$this->pick($mc,['order_id']); if(!$pk||!$fk) return 0; $ids=$this->ordersFor($id,$t)->pluck($pk)->all(); if(!$ids) return 0; $q=DB::table('order_menus')->whereIn($fk,$ids); $status=$this->pick($mc,['kds_status','item_status','status','status_name','order_menu_status','cooking_status']); $bool=$this->pick($mc,['is_ready','ready','completed','is_completed']); if($status) $q->where(fn($qq)=>$qq->where($status,'like','%ready%')->orWhere($status,'like','%complete%')->orWhere($status,'like','%done%')->orWhere($status,'like','%serve%')); elseif($bool) $q->where($bool,1); else return 0; $served=$this->pick($mc,['served','is_served']); if($served) $q->where(fn($qq)=>$qq->whereNull($served)->orWhere($served,0)); return (int)$q->count(); } catch (\Throwable $e){ return 0; } }
    protected function reservation($id){ $info=['count'=>0,'next_time'=>null,'ids'=>[]]; if(!Schema::hasTable('reservations')) return $info; try{ $ids=[]; if(Schema::hasTable('reservation_tables')) $ids=DB::table('reservation_tables')->where('table_id',$id)->pluck('reservation_id')->all(); $c=$this->columns('reservations'); $q=DB::table('reservations')->where(function($qq) use($id,$ids,$c){ if(in_array('table_id',$c,true)) $qq->orWhere('table_id',$id); if($ids) $qq->orWhereIn('reservation_id',$ids); }); if(in_array('reserve_date',$c,true)) $q->where('reserve_date',date('Y-m-d')); if(in_array('status_id',$c,true)) $q->where('status_id','>=',1); $rows=$q->limit(20)->get(); $times=[]; $res=[]; foreach($rows as $row){ $r=(array)$row; if(!empty($r['reserve_time'])) $times[]=(string)$r['reserve_time']; if(!empty($r['reservation_id'])) $res[]=(int)$r['reservation_id']; } sort($times); return ['count'=>count($rows),'next_time'=>$times[0]??null,'ids'=>$res]; } catch (\Throwable $e){ return $info; } }
    protected function attention($id){ $count=0; $types=[]; if(Schema::hasTable('notifications')){ try{ $c=$this->columns('notifications'); if(in_array('table_id',$c,true)){ $q=DB::table('notifications')->where('table_id',$id); if(in_array('status',$c,true)) $q->whereIn('status',['new','in_progress']); foreach($q->limit(20)->get() as $row){ $r=(array)$row; $count++; if(!empty($r['type'])) $types[]=$r['type']; } } } catch (\Throwable $e){} } foreach(['table_notes','ti_table_notes'] as $tn){ if(Schema::hasTable($tn)){ try{ $c=$this->columns($tn); if(in_array('table_id',$c,true)){ $q=DB::table($tn)->where('table_id',$id); if(in_array('status',$c,true)) $q->whereIn('status',['new']); $n=(int)$q->count(); if($n){ $count+=$n; $types[]='note'; } } } catch (\Throwable $e){} } } return ['count'=>$count,'types'=>array_values(array_unique($types))]; }

    protected function ensureBridge(){ if(!Schema::hasTable('pmd_waiter_table_assignments')) Schema::create('pmd_waiter_table_assignments',function($t){ $t->increments('id'); $t->integer('staff_id')->unsigned()->index(); $t->integer('table_id')->unsigned()->index(); $t->integer('location_id')->unsigned()->nullable()->index(); $t->string('section_name')->nullable(); $t->boolean('is_active')->default(1)->index(); $t->integer('assigned_by')->unsigned()->nullable(); $t->text('notes')->nullable(); $t->timestamps(); }); if(!Schema::hasTable('pmd_table_merges')) Schema::create('pmd_table_merges',function($t){ $t->increments('id'); $t->integer('primary_table_id')->index(); $t->integer('secondary_table_id')->index(); $t->string('status')->default('active')->index(); $t->integer('staff_id')->nullable()->index(); $t->text('notes')->nullable(); $t->timestamps(); }); }
