    protected function mergeMap(){ $out=[]; if(!Schema::hasTable('pmd_table_merges')) return $out; try{ foreach(DB::table('pmd_table_merges')->where('status','active')->get() as $row){ $r=(array)$row; $out[(int)$r['secondary_table_id']]=['primary_table_id'=>(int)$r['primary_table_id'],'status'=>'active']; } } catch (\Throwable $e){} return $out; }
    protected function userInfo(){ $user=null; try{ $user=AdminAuth::getUser(); } catch (\Throwable $e){ try{ $user=AdminAuth::user(); }catch(\Throwable $e2){} } $out=['id'=>null,'staff_id'=>null,'username'=>'','email'=>'']; if($user){ $a=is_object($user)&&method_exists($user,'getAttributes')?$user->getAttributes():(array)$user; $out['id']=isset($a['id'])?(int)$a['id']:(isset($a['user_id'])?(int)$a['user_id']:null); foreach(['staff_id','staffId'] as $k) if(isset($a[$k])&&is_numeric($a[$k])) $out['staff_id']=(int)$a[$k]; foreach(['username','name','login','staff_name'] as $k) if(!empty($a[$k])){ $out['username']=(string)$a[$k]; break; } foreach(['email','staff_email'] as $k) if(!empty($a[$k])){ $out['email']=(string)$a[$k]; break; } } if(!$out['staff_id']) $out['staff_id']=$out['id'] ?: 1; return $out; }
