    protected function columns($table){ if(isset($this->cols[$table])) return $this->cols[$table]; try{ $rows=DB::select('DESCRIBE `'.str_replace('`','``',$table).'`'); $out=[]; foreach($rows as $row){ $r=(array)$row; if(!empty($r['Field'])) $out[]=$r['Field']; } return $this->cols[$table]=$out; } catch (\Throwable $e){ return $this->cols[$table]=[]; } }
